package auth

import (
	"context"
	"errors"
	"maps"
	"reflect"

	"github.com/utilitywarehouse/uwos-go/iam/pdp"
	"github.com/utilitywarehouse/uwos-go/iam/principal"
	"google.golang.org/grpc/codes"
	"google.golang.org/grpc/status"
	"google.golang.org/protobuf/types/known/structpb"

	"github.com/utilitywarehouse/telecom-mobile/pkg/auth/cerbos"
	"github.com/utilitywarehouse/telecom-mobile/pkg/libdry/terrors"
	"github.com/utilitywarehouse/telecom-mobile/pkg/libdry/tlog"
)

const (
	pdpLimit       = 10 // pdp limits 10 actions per resource
	ChannelWilliam = "william"
)

type Authorizer interface {
	AuthorizeStaff(ctx context.Context, action cerbos.Action, resource cerbos.Resource, resourceID string) (*AuthStaffResponse, error)
	AuthorizeCustomer(ctx context.Context, action cerbos.Action, resource cerbos.Resource, resourceID string) (*AuthCustomerResponse, error)
	AuthorizeMultiActionStaff(ctx context.Context, actions []cerbos.Action, resource cerbos.Resource, resourceID string) (*AuthMultiActionResponse, error)
	AuthorizeMachine(ctx context.Context, action cerbos.Action, resource cerbos.Resource, resourceID string) (*AuthMachineResponse, error)
	AuthorizeAnyPrincipal(ctx context.Context, action cerbos.Action, resource cerbos.Resource, resourceID string) error
}

type pDPAuthorizer struct {
	client *pdp.Client
}

type AuthStaffResponse struct {
	RequestID      string
	Email          string
	EmployeeNumber string
	Output         map[string]*structpb.Value
}
type AuthMultiActionResponse struct {
	RequestIDs     []string
	Email          string
	EmployeeNumber string
	Effects        map[string]pdp.Effect
}

type AuthCustomerResponse struct {
	RequestID     string
	AccountNumber string
	AccountID     string
}

type AuthMachineResponse struct {
	RequestID string
	Namespace string
	PodName   string
}

func NewAuthorizer(pdpClient *pdp.Client) Authorizer {
	return &pDPAuthorizer{
		client: pdpClient,
	}
}

func (pa *pDPAuthorizer) AuthorizeStaff(ctx context.Context, action cerbos.Action, resource cerbos.Resource, resourceID string) (*AuthStaffResponse, error) {
	auth, err := pa.authorize(ctx, action, resource, resourceID)

	switch {
	case errors.Is(err, pdp.ErrUnauthenticated):
		tlog.Warn(ctx, "principal not authenticated")
		return nil, status.Error(codes.Unauthenticated, terrors.ErrUnauthenticated.Error())
	case errors.Is(err, terrors.ErrPermissionDenied):
		tlog.WithAttribute("pdp-request-id", auth.Metadata.RequestID).Warn(ctx, "authorization failed")
		return nil, status.Error(codes.PermissionDenied, terrors.ErrPermissionDenied.Error())
	case err != nil:
		tlog.WithError(err).Warn(ctx, "unexpected error from pdp auth request")
		return nil, status.Error(codes.Internal, terrors.ErrInternalServerErr.Error())
	}

	return &AuthStaffResponse{RequestID: auth.Metadata.RequestID, Email: auth.Metadata.Principal.Staff.Email, EmployeeNumber: auth.Metadata.Principal.Staff.EmployeeNumber, Output: auth.RulesOutput}, nil
}

func (pa *pDPAuthorizer) AuthorizeMultiActionStaff(ctx context.Context, actions []cerbos.Action, resource cerbos.Resource, resourceID string) (*AuthMultiActionResponse, error) {
	multiActions := [][]cerbos.Action{}
	currSlice := []cerbos.Action{}
	length := len(actions)

	for i := range actions {
		if (len(actions)-length)%pdpLimit == 0 && len(currSlice) > 0 {
			multiActions = append(multiActions, currSlice)
			currSlice = []cerbos.Action{}
		}
		length -= 1
		currSlice = append(currSlice, actions[i])

		if length < pdpLimit && i == len(actions)-1 {
			multiActions = append(multiActions, currSlice)
		}
	}

	effects := map[string]pdp.Effect{}
	requestIds := []string{}
	out := AuthMultiActionResponse{}
	for _, acts := range multiActions {
		auth, err := pa.multiActionAuthorize(ctx, acts, resource, resourceID)

		switch {
		case errors.Is(err, pdp.ErrUnauthenticated):
			tlog.Error(ctx, "principal not authenticated")
			return nil, status.Error(codes.Unauthenticated, terrors.ErrUnauthenticated.Error())
		case err != nil:
			tlog.WithError(err).Error(ctx, "unexpected error from pdp auth request")
			return nil, status.Error(codes.Internal, terrors.ErrInternalServerErr.Error())
		}

		requestIds = append(requestIds, auth.Metadata.RequestID)
		for _, results := range auth.Results {
			out.EmployeeNumber = results.Metadata.Principal.Staff.EmployeeNumber
			out.Email = results.Metadata.Principal.Staff.Email

			for _, effect := range results.Results {
				maps.Copy(effects, effect)
			}
		}
	}

	out.RequestIDs = requestIds
	out.Effects = effects

	return &out, nil
}

func (pa *pDPAuthorizer) AuthorizeCustomer(ctx context.Context, action cerbos.Action, resource cerbos.Resource, resourceID string) (*AuthCustomerResponse, error) {
	auth, err := pa.authorize(ctx, action, resource, resourceID)

	if err != nil {
		switch {
		case errors.Is(err, pdp.ErrUnauthenticated):
			tlog.Error(ctx, "principal not authenticated")
			return nil, status.Error(codes.Unauthenticated, terrors.ErrUnauthenticated.Error())
		case errors.Is(err, terrors.ErrPermissionDenied):
			tlog.WithAttribute("pdp-request-id", auth.Metadata.RequestID).Error(ctx, "authorization failed")
			return nil, status.Error(codes.PermissionDenied, terrors.ErrPermissionDenied.Error())
		case err != nil:
			tlog.WithError(err).Error(ctx, "unexpected error from pdp auth request")
			return nil, status.Error(codes.Internal, terrors.ErrInternalServerErr.Error())
		}
	}

	return &AuthCustomerResponse{
		RequestID:     auth.Metadata.RequestID,
		AccountNumber: auth.Metadata.Principal.User.Customer.AccountNumber,
		AccountID:     auth.Metadata.Principal.User.Customer.AccountID,
	}, nil
}

func (pa *pDPAuthorizer) AuthorizeMachine(ctx context.Context, action cerbos.Action, resource cerbos.Resource, resourceID string) (*AuthMachineResponse, error) {
	auth, err := pa.authorize(ctx, action, resource, resourceID)
	if err != nil {
		switch {
		case errors.Is(err, pdp.ErrUnauthenticated):
			tlog.Error(ctx, "principal not authenticated")
			return nil, status.Error(codes.Unauthenticated, terrors.ErrUnauthenticated.Error())
		case errors.Is(err, terrors.ErrPermissionDenied):
			tlog.WithAttribute("pdp-request-id", auth.Metadata.RequestID).Error(ctx, "authorization failed")
			return nil, status.Error(codes.PermissionDenied, terrors.ErrPermissionDenied.Error())
		case err != nil:
			tlog.WithError(err).Error(ctx, "unexpected error from pdp auth request")
			return nil, status.Error(codes.Internal, terrors.ErrInternalServerErr.Error())
		}
	}

	return &AuthMachineResponse{
		RequestID: auth.Metadata.RequestID,
		Namespace: auth.Metadata.Principal.Machine.K8s.Namespace,
		PodName:   auth.Metadata.Principal.Machine.K8s.PodName,
	}, nil
}

func (pa *pDPAuthorizer) AuthorizeAnyPrincipal(ctx context.Context, action cerbos.Action, resource cerbos.Resource, resourceID string) error {
	auth, err := pa.authorizeAny(ctx, action, resource, resourceID)
	if err != nil {
		switch {
		case errors.Is(err, pdp.ErrUnauthenticated):
			tlog.Error(ctx, "principal not authenticated")
			return status.Error(codes.Unauthenticated, terrors.ErrUnauthenticated.Error())
		case errors.Is(err, terrors.ErrPermissionDenied):
			tlog.WithAttribute("pdp-request-id", auth.Metadata.RequestID).Error(ctx, "authorization failed")
			return status.Error(codes.PermissionDenied, terrors.ErrPermissionDenied.Error())
		default:
			tlog.WithError(err).Error(ctx, "unexpected error from pdp auth request")
			return status.Error(codes.Internal, terrors.ErrInternalServerErr.Error())
		}
	}

	return nil
}

func (pa *pDPAuthorizer) authorizeAny(ctx context.Context, action cerbos.Action, resource cerbos.Resource, resourceID string) (pdp.MultiAuthorizeResult, error) {
	res, err := pa.client.Multi().Authorize(ctx, string(action), pdp.NewResource(string(resource), resourceID))
	if err != nil {
		return res, err
	}

	if !res.AllowedAny() {
		return res, terrors.ErrPermissionDenied
	}

	return res, nil
}

func (pa *pDPAuthorizer) authorize(ctx context.Context, action cerbos.Action, resource cerbos.Resource, resourceID string) (pdp.AuthorizeResult, error) {
	res, err := pa.client.Single().Authorize(ctx, principal.FromCtx(ctx), string(action), pdp.NewResource(string(resource), resourceID))
	if err != nil {
		return res, err
	}

	if !res.Allowed() {
		return res, terrors.ErrPermissionDenied
	}

	return res, nil
}

func (pa *pDPAuthorizer) multiActionAuthorize(ctx context.Context, actions []cerbos.Action, resource cerbos.Resource, resourceID string) (pdp.MultiAuthorizeBatchResult, error) {
	strActions := []string{}
	for _, action := range actions {
		strActions = append(strActions, string(action))
	}

	batch := []*pdp.ResourceWithActions{
		{
			Resource: &pdp.Resource{
				ResourceIdentity: pdp.ResourceIdentity{
					Kind: string(resource),
					ID:   resourceID,
				},
				Attr: nil,
			},
			Actions: strActions,
		},
	}
	return pa.client.Multi().AuthorizeBatch(ctx, batch)
}

// GetRawOutput returns the output from the named rules that matched.
func (a AuthStaffResponse) GetRawOutput(rule string) *structpb.Value {
	output, found := a.Output[rule]
	if !found {
		return structpb.NewNullValue()
	}
	return output
}

// GetBoolOutput returns the desired output as a boolean
func (a AuthStaffResponse) GetBoolOutput(rule, key string) bool {
	output := a.GetRawOutput(rule).GetStructValue().AsMap()

	if output[key] == nil {
		return false
	}
	return reflect.ValueOf(output[key]).Bool()
}
